1	const cellKey = (x: number, y: number): string => `${x},${y}`;
2	
3	const parseKey = (key: string): number[] => key.split(",").map(Number);
4	
5	export const nextGeneration = (liveCells: number[][]): number[][] => {
6	  if (liveCells.length === 0) return [];
7	
8	  const liveSet = new Set(liveCells.map(([x, y]) => cellKey(x, y)));
9	
10	  const neighborCounts = new Map<string, number>();
11	
12	  for (const [x, y] of liveCells) {
13	    for (let dx = -1; dx <= 1; dx++) {
14	      for (let dy = -1; dy <= 1; dy++) {
15	        if (dx === 0 && dy === 0) continue;
16	        const key = cellKey(x + dx, y + dy);
17	        neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
18	      }
19	    }
20	  }
21	
22	  const result: number[][] = [];
23	
24	  for (const [key, count] of neighborCounts) {
25	    if (count === 3 || (count === 2 && liveSet.has(key))) {
26	      result.push(parseKey(key));
27	    }
28	  }
29	
30	  return result;
31	};
